import { useEffect, useState } from 'react';
import { Compass, Loader2 } from 'lucide-react';
import { MediaCard } from '../../components/media/MediaCard';
import { useIntersectionObserver } from '../../hooks/useIntersectionObserver';

interface Movie {
  id: number;
  title: string;
  overview: string;
  backdrop_path: string;
  poster_path: string;
}

const Discover = () => {
  const [trending, setTrending] = useState<Movie[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [page, setPage] = useState(1);

  const loadMovies = async (pageNum: number) => {
    if (pageNum === 1) setLoading(true);
    else setLoadingMore(true);

    try {
      const res = await fetch(`http://localhost:3000/api/tmdb/trending?page=${pageNum}`);
      const data = await res.json();

      const newMovies = data.results || [];

      if (pageNum === 1) {
        setTrending(newMovies);
      } else {
        // Filter out duplicates just in case
        setTrending(prev => {
          const existingIds = new Set(prev.map(m => m.id));
          const uniqueNew = newMovies.filter((m: Movie) => !existingIds.has(m.id));
          return [...prev, ...uniqueNew];
        });
      }
      setPage(pageNum);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
      setLoadingMore(false);
    }
  };

  // Infinite Scroll Hook
  const { ref: loadMoreRef, isIntersecting } = useIntersectionObserver({
    threshold: 0.5,
    enabled: !loading && !loadingMore
  });

  useEffect(() => {
    if (isIntersecting && !loading && !loadingMore) {
      loadMovies(page + 1);
    }
  }, [isIntersecting]);

  useEffect(() => {
    loadMovies(1);
  }, []);

  if (loading) {
    return (
      <div className="h-full flex items-center justify-center text-gray-500">
        <Loader2 className="animate-spin text-apple-blue" size={40} />
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 pb-20 overflow-y-auto h-full header-scroll-mask">
      <div className="flex items-center gap-4 mb-8">
        <div className="w-12 h-12 bg-gray-800 rounded-2xl flex items-center justify-center text-apple-blue shadow-lg">
          <Compass size={24} />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white tracking-tight">Discover</h1>
          <p className="text-gray-400 text-sm mt-1">Explore what's trending worldwide</p>
        </div>
      </div>

      <div className="space-y-6">
        <h2 className="text-xl font-semibold text-gray-200 pl-1">Trending Now</h2>

        {/* fluid grid to fill gaps */}
        <div className="grid grid-cols-[repeat(auto-fill,minmax(160px,1fr))] gap-4 md:gap-6">
          {trending.map((movie) => (
            <MediaCard
              key={movie.id}
              item={{
                _id: movie.id.toString(),
                tmdbId: movie.id,
                title: movie.title,
                filename: movie.title,
                posterPath: movie.poster_path,
                isTmdb: true,
                mediaType: 'movie'
              }}
            />
          ))}
        </div>

        {/* Infinite Scroll Sentinel */}
        <div ref={loadMoreRef} className="flex justify-center py-8 min-h-[100px]">
          {loadingMore && (
            <div className="flex flex-col items-center gap-2 text-gray-500">
              <Loader2 className="animate-spin" />
              <span className="text-sm">Loading more...</span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Discover;

import { motion } from 'framer-motion';
import { History as HistoryIcon } from 'lucide-react';
import { MediaCard, type MediaItem } from '../../components/media/MediaCard';
import { useState, useEffect } from 'react';
import api from '../../lib/api';

const History = () => {
  const [items, setItems] = useState<MediaItem[]>([]);
  const [loading, setLoading] = useState(true);

  interface HistoryEntry {
    mediaId?: string;
    tmdbId?: number;
    title: string;
    posterPath?: string;
    mediaType: 'movie' | 'tv';
    watchedAt: string;
    progress?: number;
  }

  const fetchHistory = async () => {
    try {
      const res = await api.get('/history');
      const mapped: MediaItem[] = res.data.map((item: HistoryEntry) => ({
        _id: item.mediaId || item.tmdbId?.toString() || '',
        tmdbId: item.tmdbId,
        title: item.title,
        filename: item.title,
        posterPath: item.posterPath,
        mediaType: item.mediaType,
        isTmdb: !item.mediaId
      }));
      setItems(mapped);
    } catch (err) {
      console.error('Failed to load history', err);
    } finally {
      setLoading(false);
    }
  };

  // Deduplicate items for display (Safety net for existing dupes)
  const uniqueItems = items.filter((item, index, self) =>
    index === self.findIndex((t) => (
      t._id === item._id
    ))
  );

  useEffect(() => {
    fetchHistory();
  }, []);

  return (
    <div className="p-8 pb-20 overflow-y-auto h-full">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-400">
            Watch History
          </h1>
          <p className="text-gray-400 mt-1">Movies and shows you've watched</p>
        </div>
      </div>

      {/* Loading */}
      {loading && (
        <div className="flex justify-center items-center h-40">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-white"></div>
        </div>
      )}

      {/* Grid */}
      {!loading && uniqueItems.length > 0 ? (
        <motion.div
          layout
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6"
        >
          {uniqueItems.map((item, idx) => (
            <MediaCard key={`${item._id}-${idx}`} item={item} />
          ))}
        </motion.div>
      ) : !loading && (
        <div className="flex flex-col items-center justify-center py-20 text-gray-500">
          <div className="w-20 h-20 rounded-full bg-white/5 flex items-center justify-center mb-4">
            <HistoryIcon size={40} className="opacity-50" />
          </div>
          <p className="text-xl font-medium text-gray-400">No history yet</p>
          <p className="text-sm mt-2">Start watching something to see it here.</p>
        </div>
      )}
    </div>
  );
};

export default History;

import { motion } from 'framer-motion';
import { Film } from 'lucide-react';
import { MediaCard, type MediaItem } from '../../components/media/MediaCard';
import { useState, useEffect, useMemo } from 'react';
import api from '../../lib/api';
import { Select } from '../../components/ui/Select';

const Watchlist = () => {
  const [items, setItems] = useState<MediaItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [sort, setSort] = useState('date_added');

  // Define the backend response shape locally
  interface WatchlistEntry {
    mediaId?: string;
    tmdbId?: number;
    title: string;
    posterPath?: string;
    mediaType: 'movie' | 'tv';
  }

  const fetchWatchlist = async () => {
    try {
      const res = await api.get('/watchlist');
      // Map watchlist items to MediaCard format
      const mapped: MediaItem[] = res.data.map((item: WatchlistEntry) => ({
        _id: item.mediaId || item.tmdbId?.toString() || '',
        tmdbId: item.tmdbId,
        title: item.title,
        filename: item.title, // Fallback
        posterPath: item.posterPath,
        mediaType: item.mediaType,
        isTmdb: !item.mediaId // If no mediaId, it's global
      }));
      setItems(mapped);
    } catch (err) {
      console.error('Failed to load watchlist', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWatchlist();

    const handleUpdate = () => {
      fetchWatchlist();
    };

    window.addEventListener('watchlist-updated', handleUpdate);
    window.addEventListener('storage', handleUpdate); // Cross-tab sync

    return () => {
      window.removeEventListener('watchlist-updated', handleUpdate);
      window.removeEventListener('storage', handleUpdate);
    };
  }, []);

  const filteredItems = useMemo(() => {
    let result = [...items];

    // Filter
    if (filter !== 'all') {
      result = result.filter(item => item.mediaType === filter);
    }

    // Sort
    if (sort === 'title') {
      result.sort((a, b) => (a.title || a.filename || '').localeCompare(b.title || b.filename || ''));
    } else if (sort === 'release_date') {
      // Note: watchlist items currently don't store release date in the mapped object above
      // If we need true release date sorting, we should add it to the backend response or mapped object.
      // For now, fallback to title or keep original order.
      // Let's assume title for stability if date missing.
      result.sort((a, b) => (a.title || a.filename || '').localeCompare(b.title || b.filename || ''));
    } else {
      // date_added (assuming backend returns in insertion order or latest first?)
      // If backend returns latest first, default is fine.
      // If we want to reverse default (oldest first?), we can.
      // Generally 'Recent' is preferred. assuming items is already recents.
    }

    return result;
  }, [items, filter, sort]);

  return (
    <div className="p-8 pb-20 overflow-y-auto h-full">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-400">
            Watchlist
          </h1>
          <p className="text-gray-400 mt-1">Your planned movies and TV shows</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="w-32">
            <Select
              label="Type"
              value={filter}
              onChange={setFilter}
              options={[
                { label: 'All', value: 'all' },
                { label: 'Movies', value: 'movie' },
                { label: 'TV Shows', value: 'tv' },
              ]}
            />
          </div>
          <div className="w-40">
            <Select
              label="Sort By"
              value={sort}
              onChange={setSort}
              options={[
                { label: 'Date Added', value: 'date_added' },
                { label: 'Title (A-Z)', value: 'title' },
              ]}
            />
          </div>
        </div>
      </div>

      {/* Loading */}
      {loading && (
        <div className="flex justify-center items-center h-40">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-white"></div>
        </div>
      )}

      {/* Grid */}
      {!loading && filteredItems.length > 0 ? (
        <motion.div
          layout
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6"
        >
          {filteredItems.map((item) => (
            <MediaCard key={item._id} item={item} />
          ))}
        </motion.div>
      ) : !loading && (
        <div className="flex flex-col items-center justify-center py-20 text-gray-500">
          <div className="w-20 h-20 rounded-full bg-white/5 flex items-center justify-center mb-4">
            <Film size={40} className="opacity-50" />
          </div>
          <p className="text-xl font-medium text-gray-400">No items found</p>
          <p className="text-sm mt-2">Try adjusting your filters or add some content.</p>
        </div>
      )}
    </div>
  );
};

export default Watchlist;
